1	type Cell = [number, number]; // [x, y]
2	
3	const toKey = ([x, y]: Cell): string => `${x},${y}`;
4	const fromKey = (key: string): Cell => {
5	  const [x, y] = key.split(",").map(Number);
6	  return [x, y];
7	};
8	
9	const isAliveNextGeneration = (alive: boolean, neighbors: number): boolean =>
10	  neighbors === 3 || (alive && neighbors === 2);
11	
12	export function nextGeneration(cells: Cell[]): Cell[] {
13	  const living = new Set(cells.map(toKey));
14	
15	  const neighborCounts = new Map<string, number>();
16	  for (const [x, y] of cells) {
17	    for (let dx = -1; dx <= 1; dx++) {
18	      for (let dy = -1; dy <= 1; dy++) {
19	        if (dx === 0 && dy === 0) continue;
20	        const key = toKey([x + dx, y + dy]);
21	        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
22	      }
23	    }
24	  }
25	
26	  const nextCells: Cell[] = [];
27	  for (const [key, count] of neighborCounts) {
28	    if (isAliveNextGeneration(living.has(key), count)) {
29	      nextCells.push(fromKey(key));
30	    }
31	  }
32	  return nextCells;
33	}
